#include "controller.h"

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_PRESSURE_LOW_THRESHOLD 40
#define CONTROLLER_PRESSURE_HIGH_THRESHOLD 60
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

static void controller_set_safe_vent(controller_t *controller)
{
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_vent(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    if (controller->has_valid_pressure && (now_ms - controller->last_pressure_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }
    if (controller->has_valid_door && (now_ms - controller->last_door_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }
    return false;
}

static void controller_apply_pressure_input(controller_t *controller, int pressure_kpa, uint32_t now_ms)
{
    if (pressure_kpa < 0 || pressure_kpa > 120) {
        controller->has_valid_pressure = false;
        controller->last_pressure_kpa = 0;
        controller->last_pressure_ms = 0U;
        return;
    }

    controller->has_valid_pressure = true;
    controller->last_pressure_kpa = pressure_kpa;
    controller->last_pressure_ms = now_ms;
}

static void controller_apply_door_input(controller_t *controller, bool door_closed, uint32_t now_ms)
{
    controller->has_valid_door = true;
    controller->door_closed = door_closed;
    controller->last_door_ms = now_ms;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    uint32_t now_ms = input.now_ms;

    bool previous_compressor_on = controller->compressor_on;
    bool previous_vent_open = controller->vent_open;
    controller_state_t previous_state = controller->state;

    /* Check for sensor timeout first - forces safe vent state */
    if (controller_check_sensor_timeout(controller, now_ms)) {
        controller_set_safe_vent(controller);
        output.timed_out = true;
        goto return_output;
    }

    /* Apply input updates */
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller_apply_pressure_input(controller, input.pressure_kpa, now_ms);
        break;
    case CONTROLLER_INPUT_DOOR_OPEN:
        controller_apply_door_input(controller, false, now_ms);
        /* Door open -> safe vent state */
        controller_set_safe_vent(controller);
        goto return_output;
    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller_apply_door_input(controller, true, now_ms);
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        /* Reset sensor validity on invalid input */
        controller->has_valid_pressure = false;
        controller->last_pressure_kpa = 0;
        controller->last_pressure_ms = 0U;
        controller->has_valid_door = false;
        controller->door_closed = false;
        controller_set_safe_vent(controller);
        goto return_output;
    case CONTROLLER_INPUT_NONE:
        /* No new input - just check for timeout */
        break;
    default:
        break;
    }

    /* Now apply control policy based on current state */

    /* If we don't have both sensors valid, stay in safe vent */
    if (!controller->has_valid_pressure || !controller->has_valid_door) {
        controller_set_safe_vent(controller);
        goto return_output;
    }

    /* Door is closed and both sensors valid - apply control policy */
    if (controller->door_closed) {
        int pressure = controller->last_pressure_kpa;

        if (pressure < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            /* Pressurize: compressor on, vent closed */
            controller->compressor_on = true;
            controller->vent_open = false;
            controller->state = CONTROLLER_STATE_PRESSURIZING;
        } else if (pressure > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            /* Relieve: compressor off, vent open */
            controller->compressor_on = false;
            controller->vent_open = true;
            controller->state = CONTROLLER_STATE_RELIEVING;
        } else {
            /* Holding: preserve previous safe output */
            controller->state = CONTROLLER_STATE_HOLDING;
        }
    } else {
        /* Door is open - stay in safe vent state */
        controller_set_safe_vent(controller);
    }

return_output:
    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PRESSURIZING:
        return "STATE PRESSURIZING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_RELIEVING:
        return "STATE RELIEVING";
    case CONTROLLER_STATE_SAFE_VENT:
    default:
        return "STATE SAFE_VENT";
    }
}

