#include <stdio.h>
#include <stdint.h>

typedef enum {
    CONTROLLER_STATE_SAFE_VENT = 0,
    CONTROLLER_STATE_PRESSURIZING,
    CONTROLLER_STATE_HOLDING,
    CONTROLLER_STATE_RELIEVING,
} controller_state_t;

typedef struct {
    int has_valid_pressure;
    int last_pressure_kpa;
    uint32_t last_pressure_ms;
    int has_valid_door;
    int door_closed;
    uint32_t last_door_ms;
    controller_state_t state;
    int compressor_on;
    int vent_open;
} controller_t;

static void controller_set_safe_vent(controller_t *controller)
{
    printf("DEBUG: Setting SAFE_VENT\n");
    controller->compressor_on = 0;
    controller->vent_open = 1;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) return;
    controller_set_safe_vent(controller);
    controller->has_valid_pressure = 0;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0;
    controller->has_valid_door = 0;
    controller->door_closed = 0;
    controller->last_door_ms = 0;
}

void controller_step_debug(controller_t *controller, int input_kind, int pressure, int door_closed, uint32_t now_ms)
{
    printf("DEBUG: Input kind=%d, pressure=%d, door_closed=%d, now_ms=%lu\n", 
           input_kind, pressure, door_closed, (unsigned long)now_ms);

    // Check for timeout
    int timed_out = 0;
    if (controller->has_valid_pressure && (now_ms - controller->last_pressure_ms) > 1000) {
        timed_out = 1;
    }
    if (controller->has_valid_door && (now_ms - controller->last_door_ms) > 1000) {
        timed_out = 1;
    }

    if (timed_out) {
        printf("DEBUG: Timeout detected!\n");
        controller_set_safe_vent(controller);
        return;
    }

    // Apply input updates
    switch (input_kind) {
    case 0:  // NONE
        break;
    case 1:  // PRESSURE
        if (pressure < 0 || pressure > 120) {
            controller->has_valid_pressure = 0;
            controller->last_pressure_kpa = 0;
            controller->last_pressure_ms = 0;
        } else {
            controller->has_valid_pressure = 1;
            controller->last_pressure_kpa = pressure;
            controller->last_pressure_ms = now_ms;
        }
        break;
    case 2:  // DOOR_OPEN
        controller->has_valid_door = 1;
        controller->door_closed = 0;
        controller->last_door_ms = now_ms;
        controller_set_safe_vent(controller);
        return;
    case 3:  // DOOR_CLOSED
        controller->has_valid_door = 1;
        controller->door_closed = 1;
        controller->last_door_ms = now_ms;
        break;
    case 4:  // SENSOR_TIMEOUT
    case 5:  // INVALID_PRESSURE
    case 6:  // INVALID_DOOR
        controller->has_valid_pressure = 0;
        controller->last_pressure_kpa = 0;
        controller->last_pressure_ms = 0;
        controller->has_valid_door = 0;
        controller->door_closed = 0;
        controller_set_safe_vent(controller);
        return;
    }

    // Apply control policy
    if (!controller->has_valid_pressure || !controller->has_valid_door) {
        printf("DEBUG: Not both sensors valid, setting SAFE_VENT\n");
        controller_set_safe_vent(controller);
        return;
    }

    if (controller->door_closed) {
        int pressure = controller->last_pressure_kpa;
        if (pressure < 40) {
            printf("DEBUG: Pressurizing (pressure=%d < 40)\n", pressure);
            controller->compressor_on = 1;
            controller->vent_open = 0;
            controller->state = CONTROLLER_STATE_PRESSURIZING;
        } else if (pressure > 60) {
            printf("DEBUG: Relieving (pressure=%d > 60)\n", pressure);
            controller->compressor_on = 0;
            controller->vent_open = 1;
            controller->state = CONTROLLER_STATE_RELIEVING;
        } else {
            printf("DEBUG: Holding (40 <= pressure <= 60)\n");
            controller->state = CONTROLLER_STATE_HOLDING;
        }
    } else {
        printf("DEBUG: Door open, setting SAFE_VENT\n");
        controller_set_safe_vent(controller);
    }

    printf("DEBUG: Final state=%d, compressor=%d, vent=%d\n", 
           controller->state, controller->compressor_on, controller->vent_open);
}

int main() {
    controller_t ctrl = {0};
    controller_init(&ctrl);

    printf("=== Initial state ===\n");
    printf("State: SAFE_VENT, compressor=0, vent=1\n\n");

    // Step 1: Door closed
    printf("=== Step 1: Door closed ===\n");
    controller_step_debug(&ctrl, 3, 0, 1, 100);  // now_ms=100

    // Step 2: Pressure 35
    printf("\n=== Step 2: Pressure 35 ===\n");
    controller_step_debug(&ctrl, 1, 35, 0, 150);  // now_ms=150 (50ms later)

    // Step 3: Heartbeat (NONE)
    printf("\n=== Step 3: Heartbeat ===\n");
