    """Extract the first COMPRESSOR/VENT pair that appears after any STATE lines."""
    # Find the last STATE line index
    state_indices = [i for i, line in enumerate(lines) if "STATE" in line and line.startswith("DBG STATE")]

    if not state_indices:
        return False, False

    last_state_idx = max(state_indices)

    # Look for ACT lines after the last STATE line
    compressor_line = None
    vent_line = None

    for i in range(last_state_idx + 1, len(lines)):
        line = lines[i]
        if line.startswith("ACT COMPRESSOR "):
            compressor_line = line
        elif line.startswith("ACT VENT "):
            vent_line = line

        # If we have both, return them
        if compressor_line and vent_line:
            break

    # If no ACT lines after STATE, use the most recent from before
    if not compressor_line or not vent_line:
        for line in reversed(lines[:last_state_idx]):
            if line.startswith("ACT COMPRESSOR "):
                compressor_on = "ON" in line
            elif line.startswith("ACT VENT "):
